- Static hosting of model.json and shard files
- Client-side preprocessing (224x224, [-1,1]) and top-k decoding

## Code Example
```javascript
// Load and infer with a TF.js GraphModel (illustrative)
const model = await tf.loadGraphModel('/models/mobilenetv2_web/model.json');
function preprocess(img) {
  const t = tf.browser.fromPixels(img).toFloat();
  const resized = tf.image.resizeBilinear(t, [224, 224]);
  const norm = resized.div(tf.scalar(127.5)).sub(tf.scalar(1));
  return norm.expandDims(0);
}
async function infer(img) {
  const input = preprocess(img);
  const logits = model.predict(input);
  const probs = logits.softmax ? logits.softmax() : logits;
  const data = await probs.data();
  const top3 = Array.from(data).map((p, i) => ({i, p}))
    .sort((a, b) => b.p - a.p)
    .slice(0, 3);
  return top3.map(x => x.i);
}
```

