  const scaleUp = latencyMs > 180 || queueDepth > 60;
  const scaleDown = latencyMs < 120 && queueDepth < 20;
  const newReplicas = Math.max(1, replicas + (scaleUp ? 1 : (scaleDown ? -1 : 0)));
