## Code Example

```python
import tensorflow as tf
from tensorflow_serving.apis import predict_pb2
import prometheus_client
from opentelemetry import trace

# Prometheus metrics
LATENCY_HISTOGRAM = prometheus_client.Histogram(
    'inference_latency_seconds', 'Inference latency by device', ['device']
)
BATCH_SIZE_GAUGE = prometheus_client.Gauge(
    'dynamic_batch_size', 'Current batch size'
)
ERROR_COUNTER = prometheus_client.Counter(
    'inference_errors_total', 'Total inference errors', ['device', 'error_type']
)

class FraudDetectionInference:
    def __init__(self):
        self.tracer = trace.get_tracer(__name__)
        self.use_gpu = tf.config.list_physical_devices('GPU')
        self.model = self._load_model()

    def _load_model(self):
        return tf.keras.models.load_model('fraud_detection_model')

    @LATENCY_HISTOGRAM.time()
    def predict(self, inputs):
        with self.tracer.start_as_current_span('fraud_detection'):
            try:
                if self.use_gpu:
                    return self._gpu_inference(inputs)
                else:
                    return self._cpu_inference(inputs)
            except Exception as e:
                ERROR_COUNTER.labels(
                    device='gpu' if self.use_gpu else 'cpu',
                    error_type=type(e).__name__
                ).inc()
                # Fallback to CPU on GPU failures
                return self._cpu_inference(inputs)
```

